import json
cases = var_call_nzXY9IeyzJ26if0z9UbyKD8b
accounts = var_call_YWa4eGeCCZUWXT3QS9htQWRy
acc_state = {a['Id'].lstrip('#'): a['state'] for a in accounts}
state_times = {}
state_counts = {}
for row in cases:
    acc_id = row['accountid'].lstrip('#') if row['accountid'] else None
    state = acc_state.get(acc_id)
    if not state:
        continue
    t = float(row['avg_days_to_close'])
    state_times[state] = state_times.get(state, 0.0) + t
    state_counts[state] = state_counts.get(state, 0) + 1
avg_by_state = {s: state_times[s]/state_counts[s] for s in state_times}
best_state = min(avg_by_state, key=avg_by_state.get) if avg_by_state else None
result = json.dumps(best_state)
print("__RESULT__:")
print(result)

